+            const auto sign_result = SignPSBTInput(DUMMY_SIGNING_PROVIDER, psbtx, i, &txdata, /*options*/{}, &out_missing_data);
             bool complete = sign_result.has_value();

             // Things are missing
             if (!complete) {
-                input_analysis.missing_pubkeys = outdata.missing_pubkeys;
